// ─── PULSE SCORE ENGINE ───────────────────────────────────────────────────────
const calcPulseScore = (empId, encuestas) => {
  const enc = encuestas.filter(e => e.empleadoId === empId);
  if (!enc.length) return { score: 50, nivel: "Atención", color: "#f59e0b", tendencia: "→" };
  const recientes = enc.sort((a, b) => b.semana.localeCompare(a.semana)).slice(0, 3);
  const avgScore = Math.round(recientes.reduce((s, e) => s + e.score, 0) / recientes.length);
  const participacion = Math.min(100, Math.round((enc.length / 5) * 100));
  const riesgoRenuncia = recientes.some(e => e.respuestas?.riesgoRenuncia === "Sí, seriamente") ? -15 : recientes.some(e => e.respuestas?.riesgoRenuncia === "Algo") ? -5 : 0;
  const problemasPersonales = recientes.some(e => e.respuestas?.problemasPersonales) ? -5 : 0;
  const pulse = Math.max(0, Math.min(100, Math.round(avgScore * 0.6 + participacion * 0.3 + 10 + riesgoRenuncia + problemasPersonales)));
  let nivel = "Intervención inmediata"; let color = "#dc2626";
  if (pulse >= 90) { nivel = "Excelente"; color = "#16a34a"; }
  else if (pulse >= 80) { nivel = "Muy Bueno"; color = "#22c55e"; }
  else if (pulse >= 70) { nivel = "Estable"; color = "#4ade80"; }
  else if (pulse >= 60) { nivel = "Atención"; color = "#f59e0b"; }
  else if (pulse >= 50) { nivel = "Riesgo"; color = "#f97316"; }
  const ultDos = enc.sort((a,b)=>b.semana.localeCompare(a.semana)).slice(0,2);
  const tendencia = ultDos.length < 2 ? "→" : ultDos[0].score > ultDos[1].score ? "↑" : ultDos[0].score < ultDos[1].score ? "↓" : "→";
  return { score: pulse, nivel, color, tendencia };
};

const calcRiesgos = (empId, encuestas) => {
  const enc = encuestas.filter(e => e.empleadoId === empId).sort((a, b) => b.semana.localeCompare(a.semana));
  if (!enc.length) return { renuncia: 10, burnout: 10, emocional: 10, conflicto: 10 };
  const rec = enc.slice(0, 3);
  const avgEstres = rec.reduce((s, e) => s + (e.respuestas?.estres || 5), 0) / rec.length;
  const avgMot = rec.reduce((s, e) => s + (e.respuestas?.motivacion || 5), 0) / rec.length;
  const avgEmoc = rec.reduce((s, e) => s + (e.respuestas?.emocional || 5), 0) / rec.length;
  const renuncia = Math.min(95, Math.round(
    (rec.some(e => e.respuestas?.riesgoRenuncia === "Sí, seriamente") ? 60 : rec.some(e => e.respuestas?.riesgoRenuncia === "Algo") ? 30 : 10) +
    (10 - avgMot) * 3 + (10 - avgEmoc) * 2
  ));
  const burnout = Math.min(95, Math.round((avgEstres / 10) * 50 + (10 - avgMot) * 4 + (rec.some(e => !e.respuestas?.cargaManejable) ? 20 : 0)));
  const emocional = Math.min(95, Math.round((10 - avgEmoc) * 8 + (rec.some(e => e.respuestas?.problemasPersonales) ? 20 : 0)));
  const conflicto = Math.min(95, Math.round((10 - (rec.reduce((s,e)=>s+(e.respuestas?.satisfaccion||5),0)/rec.length)) * 5 + avgEstres * 3));
  return { renuncia, burnout, emocional, conflicto };
};

// ─── AI CALL ──────────────────────────────────────────────────────────────────
const callAI = async (prompt, systemPrompt = "") => {
  const response = await fetch("https://api.anthropic.com/v1/messages", {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify({
      model: "claude-sonnet-4-20250514",
      max_tokens: 1000,
      system: systemPrompt || "Eres el motor de IA de McDental Pulse, un sistema de bienestar organizacional para una clínica dental. Respondes siempre en español, de forma concisa, profesional y empática. Nunca diagnosticas, solo sugieres intervenciones. Tus respuestas van dirigidas a psicólogas o administradores.",
      messages: [{ role: "user", content: prompt }]
    })
  });
  const data = await response.json();
  return data.content?.map(c => c.text || "").join("") || "Sin respuesta";
};

